// Re-package a CoAP Observe notification as an MQTT telemetry publish
// for the same room. Keeps topic structure identical to native MQTT
// nodes so ThingsBoard sees a unified stream.
let payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    try { payload = JSON.parse(payload.toString('utf8')); } catch (e) { return null; }
}
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (e) { return null; }
}
const sensorId = (payload && payload.sensor_id) || '';
const m = sensorId.match(/^b(\d{2})-f(\d{2})-r(\d+)$/);
if (!m) { return null; }
const floor = '03';
const roomCode = m[3];
msg.topic = `campus/b01/f${floor}/r${roomCode}/telemetry`;
msg.qos = 1;
msg.retain = false;
msg.payload = payload;
// Track for edge thinning
let bucket = flow.get('thinBucket') || {temp: [], hum: [], n: 0};
if (typeof payload.temperature === 'number') bucket.temp.push(payload.temperature);
if (typeof payload.humidity === 'number') bucket.hum.push(payload.humidity);
bucket.n += 1;
flow.set('thinBucket', bucket);
return msg;

// Received a CoAP ACK from the room; republish a .../response
// message so ThingsBoard can confirm the command landed.
let payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    try { payload = JSON.parse(payload.toString('utf8')); } catch (e) { payload = { raw: payload.toString('utf8') }; }
}
const topicBase = (msg._cmd_topic || '').replace(/\/cmd$/, '');
if (!topicBase) return null;
msg.topic = `${topicBase}/response`;
msg.qos = 1;
msg.retain = false;
msg.payload = { status: 'ok', from: 'coap-ack', data: payload };
return msg;

// Translate MQTT command (campus/b01/fNN/rXXX/cmd) into a CoAP PUT
// (Confirmable) request aimed at the virtual node's /actuators/hvac
// resource. Emits the CoAP request message for the coap-request node.
const PORT_MAP = {
    311: 5704,
    312: 5705,
    313: 5706,
    314: 5707,
    315: 5708,
    316: 5709,
    317: 5710,
    318: 5711,
    319: 5712,
    320: 5713,
};
const m = (msg.topic || '').match(/^campus\/b01\/f(\d{2})\/r(\d+)\/cmd$/);
if (!m) { return null; }
const floorStr = '03';
const roomCode = parseInt(m[2], 10);
const port = PORT_MAP[roomCode];
if (!port) {
    node.warn(`cmd for unknown CoAP room ${roomCode}`);
    return null;
}
const engineHost = global.get('engineHost') || 'engine';
msg.method = 'PUT';
msg.observe = false;
msg.options = { 'Content-Format': 'application/json' };
msg.url = `coap://${engineHost}:${port}/f${floorStr}/r${roomCode}/actuators/hvac`;
msg._cmd_topic = msg.topic;
msg._room_code = roomCode;
msg._floor = floorStr;
// Keep payload as JSON object; coap-request serialises
return msg;

// Drop MQTT commands whose DUP flag is set AND that we've already
// processed within the last 60 seconds. Uses a per-flow LRU map
// keyed by (topic, command_id).
const CACHE_KEY = 'dupCache';
const cache = flow.get(CACHE_KEY) || {};
const now = Date.now();
const ttl = 60 * 1000;
// Evict expired
for (const k of Object.keys(cache)) {
    if (cache[k] < now - ttl) delete cache[k];
}
const payload = (typeof msg.payload === 'string') ? (function () { try { return JSON.parse(msg.payload); } catch (e) { return null; } })() : msg.payload;
if (!payload || typeof payload !== 'object') { return null; }
const cmdId = payload.command_id || `${msg.topic}:${msg._msgid}`;
const dupFlag = !!(msg.dup || (msg.fixed && msg.fixed.dup));
const key = `${msg.topic}|${cmdId}`;
if (cache[key] && dupFlag) {
    node.warn(`DUP drop key=${key}`);
    return null;
}
cache[key] = now;
flow.set(CACHE_KEY, cache);
msg.payload = payload;
return msg;

// Compute and publish a 60-second floor-level state summary to
// reduce network congestion (campus/b01/fNN/summary).  Also
// powers ThingsBoard's Floor Health card.
const bucket = flow.get('thinBucket') || {temp: [], hum: [], n: 0};
function avg(xs) { return xs.length ? xs.reduce((a,b)=>a+b,0) / xs.length : null; }
const summary = {
    floor: 'f03',
    window_sec: 60,
    samples: bucket.n,
    avg_temperature: avg(bucket.temp),
    avg_humidity: avg(bucket.hum),
    timestamp: Math.floor(Date.now() / 1000)
};
flow.set('thinBucket', {temp: [], hum: [], n: 0});
msg.topic = 'campus/b01/f03/summary';
msg.qos = 1;
msg.retain = true;
msg.payload = summary;
return msg;

// Local autonomy: if a room reports occupancy=false AND the cloud
// connection is degraded, emit a lights-off MQTT cmd locally so
// the gateway keeps controlling actuators even when offline.
const payload = msg.payload || {};
if (typeof payload !== 'object') return null;
const cloudOk = (flow.get('cloudOk') !== false);
if (payload.occupancy === false && payload.lighting_dimmer > 10 && !cloudOk) {
    const sid = payload.sensor_id || '';
    const m = sid.match(/^b(\d{2})-f(\d{2})-r(\d+)$/);
    if (!m) return null;
    const local = { topic: `campus/b01/f${m[2]}/r${m[3]}/cmd`, qos: 2, payload: {lighting_dimmer: 0, command_id: `autonomy-${sid}-${Date.now()}`} };
    return local;
}
return null;
